.aihlegal-header {
  --aihlegal-offset: 0px;
  --aihlegal-ink: var(--bs-dark, #152132);
  --aihlegal-paper: var(--bs-body-bg, #fff);
  --aihlegal-accent: var(--bs-primary, #8b6a36);
  --aihlegal-border: var(--bs-border-color, #dfe3e8);
  position: sticky;
  top: var(--aihlegal-offset);
  z-index: 1040;
  width: 100%;
  color: var(--bs-body-color, #1d2835);
  font-family: var(--bs-body-font-family, system-ui, sans-serif);
  isolation: isolate;
}

body.admin-bar .aihlegal-header {
  --aihlegal-offset: 32px;
}

.aihlegal-header *,
.aihlegal-header *::before,
.aihlegal-header *::after {
  box-sizing: border-box;
}

.aihlegal-container {
  width: min(calc(100% - 2rem), 1380px);
  margin-inline: auto;
}

.aihlegal-skip-link {
  position: fixed;
  top: 0.5rem;
  left: 0.5rem;
  z-index: 99999;
  padding: 0.75rem 1rem;
  color: var(--sbin-primary-contrast, #fff);
  background: var(--bs-primary, #8b6a36);
  border-radius: var(--bs-border-radius, 0.375rem);
  transform: translateY(-150%);
}

.aihlegal-skip-link:focus {
  transform: translateY(0);
}

.aihlegal-topbar {
  color: var(--bs-light, #f8f9fa);
  background: var(--aihlegal-ink);
  border-bottom: 1px solid color-mix(in srgb, var(--bs-light, #fff) 14%, transparent);
}

.aihlegal-topbar__inner {
  min-height: 36px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1.5rem;
}

.aihlegal-topbar__claim {
  margin: 0;
  font-size: 0.76rem;
  letter-spacing: 0.045em;
  opacity: 0.84;
}

.aihlegal-topbar__contacts,
.aihlegal-topbar__contacts a {
  display: flex;
  align-items: center;
}

.aihlegal-topbar__contacts {
  gap: 1.25rem;
}

.aihlegal-topbar__contacts a {
  min-height: 36px;
  gap: 0.45rem;
  color: inherit;
  font-size: 0.78rem;
  font-weight: 650;
  text-decoration: none;
  white-space: nowrap;
}

.aihlegal-topbar__contacts svg {
  width: 14px;
  height: 14px;
  fill: currentColor;
}

.aihlegal-navbar {
  position: relative;
  background: var(--aihlegal-paper);
  border-bottom: 1px solid var(--aihlegal-border);
  box-shadow: 0 0.75rem 2.25rem rgba(var(--bs-dark-rgb, 21, 33, 50), 0.08);
  transition: box-shadow 180ms ease;
}

.aihlegal-header[data-scrolled="true"] .aihlegal-navbar {
  box-shadow: 0 0.85rem 2.5rem rgba(var(--bs-dark-rgb, 21, 33, 50), 0.16);
}

.aihlegal-navbar__inner {
  min-height: 88px;
  display: grid;
  grid-template-columns: minmax(240px, 1fr) auto minmax(220px, 1fr);
  align-items: center;
  gap: clamp(1rem, 2vw, 2.25rem);
}

.aihlegal-brand {
  width: max-content;
  max-width: 100%;
  display: inline-flex;
  align-items: center;
  gap: 0.85rem;
  color: var(--aihlegal-ink);
  text-decoration: none;
}

.aihlegal-brand__mark {
  width: 48px;
  height: 48px;
  display: grid;
  place-items: center;
  flex: 0 0 auto;
  color: var(--sbin-primary-contrast, #fff);
  background: var(--aihlegal-ink);
  border: 1px solid color-mix(in srgb, var(--aihlegal-accent) 75%, var(--aihlegal-ink));
  font-family: var(--bs-headings-font-family, Georgia, serif);
  font-size: 1rem;
  letter-spacing: 0.08em;
}

.aihlegal-brand__copy {
  display: grid;
  gap: 0.16rem;
  line-height: 1.1;
}

.aihlegal-brand__copy strong {
  font-family: var(--bs-headings-font-family, Georgia, serif);
  font-size: clamp(1rem, 1.25vw, 1.2rem);
  font-weight: var(--sbin-headings-weight, 650);
  letter-spacing: 0.015em;
}

.aihlegal-brand__copy small {
  color: color-mix(in srgb, var(--aihlegal-ink) 70%, transparent);
  font-size: 0.7rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
}

.aihlegal-navigation {
  display: flex;
  align-items: stretch;
  justify-content: center;
  gap: clamp(0.25rem, 0.75vw, 0.8rem);
}

.aihlegal-navigation > a,
.aihlegal-nav-trigger {
  min-height: 48px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.42rem;
  padding: 0.6rem clamp(0.45rem, 0.7vw, 0.75rem);
  color: var(--aihlegal-ink);
  background: transparent;
  border: 0;
  font: inherit;
  font-size: 0.79rem;
  font-weight: 700;
  letter-spacing: 0.035em;
  line-height: 1.2;
  text-decoration: none;
  text-transform: uppercase;
  white-space: nowrap;
  cursor: pointer;
}

.aihlegal-navigation > a,
.aihlegal-nav-group {
  position: relative;
}

.aihlegal-navigation > a::after,
.aihlegal-nav-group::after {
  content: "";
  position: absolute;
  right: 0.55rem;
  bottom: 0;
  left: 0.55rem;
  height: 2px;
  background: var(--aihlegal-accent);
  transform: scaleX(0);
  transition: transform 180ms ease;
}

.aihlegal-navigation > a:hover::after,
.aihlegal-navigation > a:focus-visible::after,
.aihlegal-navigation > a[aria-current="page"]::after,
.aihlegal-nav-group:hover::after,
.aihlegal-nav-group:focus-within::after {
  transform: scaleX(1);
}

.aihlegal-nav-trigger svg {
  width: 10px;
  fill: none;
  stroke: currentColor;
  stroke-width: 1.7;
  transition: transform 180ms ease;
}

.aihlegal-nav-trigger[aria-expanded="true"] svg {
  transform: rotate(180deg);
}

.aihlegal-megamenu {
  position: absolute;
  top: calc(100% + 20px);
  left: 50%;
  width: min(780px, calc(100vw - 3rem));
  display: grid;
  grid-template-columns: 0.85fr 1.6fr;
  color: var(--bs-body-color, #1d2835);
  background: var(--aihlegal-paper);
  border: 1px solid var(--aihlegal-border);
  box-shadow: 0 1.5rem 4rem rgba(var(--bs-dark-rgb, 21, 33, 50), 0.2);
  opacity: 0;
  visibility: hidden;
  transform: translate(-50%, -0.6rem);
  transition: opacity 180ms ease, transform 180ms ease, visibility 180ms ease;
  pointer-events: none;
}

.aihlegal-nav-group:hover .aihlegal-megamenu,
.aihlegal-nav-group:focus-within .aihlegal-megamenu,
.aihlegal-nav-group.is-open .aihlegal-megamenu {
  opacity: 1;
  visibility: visible;
  transform: translate(-50%, 0);
  pointer-events: auto;
}

.aihlegal-megamenu__intro {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  gap: 0.9rem;
  padding: 2rem;
  color: var(--bs-light, #f8f9fa);
  background: var(--aihlegal-ink);
}

.aihlegal-megamenu__intro span {
  color: color-mix(in srgb, var(--aihlegal-accent) 75%, var(--bs-light, #fff));
  font-size: 0.72rem;
  font-weight: 750;
  letter-spacing: 0.12em;
  text-transform: uppercase;
}

.aihlegal-megamenu__intro strong {
  font-family: var(--bs-headings-font-family, Georgia, serif);
  font-size: 1.35rem;
  line-height: 1.35;
}

.aihlegal-megamenu__intro a {
  margin-top: auto;
  color: inherit;
  font-size: 0.82rem;
  font-weight: 700;
  text-underline-offset: 0.25rem;
}

.aihlegal-megamenu__links {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  padding: 1rem;
}

.aihlegal-megamenu__links a {
  display: grid;
  gap: 0.35rem;
  align-content: start;
  min-height: 116px;
  padding: 1.15rem;
  color: inherit;
  border: 1px solid transparent;
  text-decoration: none;
}

.aihlegal-megamenu__links a:hover,
.aihlegal-megamenu__links a:focus-visible {
  background: color-mix(in srgb, var(--aihlegal-accent) 7%, var(--aihlegal-paper));
  border-color: color-mix(in srgb, var(--aihlegal-accent) 24%, var(--aihlegal-border));
}

.aihlegal-megamenu__links strong {
  color: var(--aihlegal-ink);
  font-family: var(--bs-headings-font-family, Georgia, serif);
  font-size: 1rem;
}

.aihlegal-megamenu__links span {
  color: color-mix(in srgb, var(--bs-body-color, #1d2835) 72%, transparent);
  font-size: 0.78rem;
  line-height: 1.55;
}

.aihlegal-actions {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: 0.7rem;
}

.aihlegal-search,
.aihlegal-cta,
.aihlegal-menu-toggle {
  min-height: 46px;
}

.aihlegal-search {
  width: 46px;
  display: grid;
  place-items: center;
  color: var(--aihlegal-ink);
  border: 1px solid var(--aihlegal-border);
  border-radius: 50%;
  text-decoration: none;
}

.aihlegal-search svg {
  width: 19px;
  fill: none;
  stroke: currentColor;
  stroke-width: 1.8;
}

.aihlegal-cta {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: var(--sbin-btn-padding-y, 0.8rem) var(--sbin-btn-padding-x, 1.2rem);
  color: var(--sbin-primary-contrast, #fff);
  background: var(--aihlegal-ink);
  border: 1px solid var(--aihlegal-ink);
  border-radius: var(--sbin-btn-border-radius, 0);
  font-size: 0.79rem;
  font-weight: var(--sbin-btn-font-weight, 750);
  letter-spacing: 0.03em;
  text-decoration: none;
  text-transform: uppercase;
  white-space: nowrap;
}

.aihlegal-cta:hover,
.aihlegal-cta:focus-visible {
  color: var(--sbin-primary-contrast, #fff);
  background: color-mix(in srgb, var(--aihlegal-ink) 84%, var(--aihlegal-accent));
}

.aihlegal-menu-toggle {
  display: none;
  align-items: center;
  gap: 0.7rem;
  justify-self: end;
  padding: 0.65rem 0.85rem;
  color: var(--aihlegal-ink);
  background: transparent;
  border: 1px solid var(--aihlegal-border);
  border-radius: var(--sbin-btn-border-radius, 0);
  font: inherit;
  font-size: 0.78rem;
  font-weight: 750;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

.aihlegal-menu-toggle__icon,
.aihlegal-menu-toggle__icon::before,
.aihlegal-menu-toggle__icon::after {
  width: 20px;
  height: 2px;
  display: block;
  background: currentColor;
  transition: transform 180ms ease, opacity 180ms ease;
}

.aihlegal-menu-toggle__icon {
  position: relative;
}

.aihlegal-menu-toggle__icon::before,
.aihlegal-menu-toggle__icon::after {
  content: "";
  position: absolute;
  left: 0;
}

.aihlegal-menu-toggle__icon::before {
  top: -6px;
}

.aihlegal-menu-toggle__icon::after {
  top: 6px;
}

.aihlegal-menu-toggle[aria-expanded="true"] .aihlegal-menu-toggle__icon {
  background: transparent;
}

.aihlegal-menu-toggle[aria-expanded="true"] .aihlegal-menu-toggle__icon::before {
  top: 0;
  transform: rotate(45deg);
}

.aihlegal-menu-toggle[aria-expanded="true"] .aihlegal-menu-toggle__icon::after {
  top: 0;
  transform: rotate(-45deg);
}

.aihlegal-header a:focus-visible,
.aihlegal-header button:focus-visible,
.aihlegal-skip-link:focus-visible {
  outline: 3px solid color-mix(in srgb, var(--aihlegal-accent) 55%, transparent);
  outline-offset: 3px;
}

@media (max-width: 1240px) {
  .aihlegal-navbar__inner {
    grid-template-columns: minmax(230px, 1fr) auto;
  }

  .aihlegal-menu-toggle {
    display: inline-flex;
  }

  .aihlegal-navigation {
    position: absolute;
    top: 100%;
    right: 1rem;
    left: 1rem;
    max-height: calc(100vh - var(--aihlegal-offset) - 124px);
    display: block;
    overflow-y: auto;
    padding: 0.75rem;
    background: var(--aihlegal-paper);
    border: 1px solid var(--aihlegal-border);
    box-shadow: 0 1.5rem 4rem rgba(var(--bs-dark-rgb, 21, 33, 50), 0.2);
    opacity: 0;
    visibility: hidden;
    transform: translateY(-0.5rem);
    transition: opacity 180ms ease, transform 180ms ease, visibility 180ms ease;
    pointer-events: none;
  }

  .aihlegal-navigation.is-open {
    opacity: 1;
    visibility: visible;
    transform: translateY(0);
    pointer-events: auto;
  }

  .aihlegal-navigation > a,
  .aihlegal-nav-trigger {
    width: 100%;
    justify-content: space-between;
    padding: 0.75rem 0.85rem;
    text-align: left;
  }

  .aihlegal-navigation > a::after,
  .aihlegal-nav-group::after {
    display: none;
  }

  .aihlegal-megamenu {
    position: static;
    width: 100%;
    display: none;
    grid-template-columns: 1fr;
    border: 0;
    box-shadow: none;
    opacity: 1;
    visibility: visible;
    transform: none;
    pointer-events: auto;
  }

  .aihlegal-nav-group.is-open .aihlegal-megamenu {
    display: grid;
    transform: none;
  }

  .aihlegal-megamenu__intro {
    padding: 1.25rem;
  }

  .aihlegal-actions {
    display: none;
  }
}

@media (max-width: 782px) {
  body.admin-bar .aihlegal-header {
    --aihlegal-offset: 46px;
  }
}

@media (max-width: 680px) {
  .aihlegal-container {
    width: min(calc(100% - 1.25rem), 1380px);
  }

  .aihlegal-topbar__inner {
    justify-content: center;
  }

  .aihlegal-topbar__claim,
  .aihlegal-topbar__contacts a:nth-child(2) {
    display: none;
  }

  .aihlegal-navbar__inner {
    min-height: 76px;
  }

  .aihlegal-brand__mark {
    width: 42px;
    height: 42px;
  }

  .aihlegal-brand__copy strong {
    font-size: 0.94rem;
  }

  .aihlegal-brand__copy small {
    font-size: 0.62rem;
  }

  .aihlegal-menu-toggle__label {
    position: absolute;
    width: 1px;
    height: 1px;
    overflow: hidden;
    clip: rect(0 0 0 0);
    white-space: nowrap;
  }

  .aihlegal-navigation {
    right: 0.625rem;
    left: 0.625rem;
    max-height: calc(100vh - var(--aihlegal-offset) - 112px);
  }

  .aihlegal-megamenu__links {
    grid-template-columns: 1fr;
  }

  .aihlegal-megamenu__links a {
    min-height: auto;
  }
}

@media (prefers-reduced-motion: reduce) {
  .aihlegal-header *,
  .aihlegal-header *::before,
  .aihlegal-header *::after {
    scroll-behavior: auto !important;
    transition-duration: 0.01ms !important;
  }
}

